param(
    [ValidateSet(
        "audit",
        "infrastructure",
        "database",
        "backend",
        "ui",
        "sandbox",
        "cutover",
        "rollback",
        "all"
    )]
    [string]$Phase = "all",

    [switch]$DryRun,
    [switch]$ApplyDatabaseMigration,
    [switch]$KeepMercadoPagoDefault,
    [switch]$SkipInitialBuild,
    [switch]$SkipFinalBuild,
    [switch]$SkipLint,
    [switch]$SkipTests,
    [switch]$SkipSandboxValidation,
    [switch]$VerboseOutput
)

$ErrorActionPreference = "Stop"
Set-StrictMode -Version 2.0

$Utf8NoBom = New-Object System.Text.UTF8Encoding($false)
$ProjectRoot = (Get-Location).Path
$Timestamp = Get-Date -Format "yyyyMMdd-HHmmss"
$BackupRoot = Join-Path $ProjectRoot (".orcaly-backups\migracao-asaas-" + $Timestamp)
$RunRoot = Join-Path $ProjectRoot (".orcaly-migration\migracao-asaas-" + $Timestamp)
$ExecutionLog = Join-Path $RunRoot "execution.log"
$BuildBeforeLog = Join-Path $RunRoot "build-before.log"
$BuildAfterLog = Join-Path $RunRoot "build-after.log"
$LintBeforeLog = Join-Path $RunRoot "lint-before.log"
$LintAfterLog = Join-Path $RunRoot "lint-after.log"
$AuditPath = Join-Path $RunRoot "audit-before.json"
$SchemaPath = Join-Path $RunRoot "schema-before.json"
$ChangedPath = Join-Path $RunRoot "changed-files.json"
$CreatedPath = Join-Path $RunRoot "created-files.json"
$RestoredPath = Join-Path $RunRoot "restored-files.json"
$DatabasePlanPath = Join-Path $RunRoot "database-plan.sql"
$SandboxPath = Join-Path $RunRoot "sandbox-validation.json"
$UnresolvedPath = Join-Path $RunRoot "unresolved-items.json"
$RollbackRuntimePath = Join-Path $RunRoot "rollback-plan.md"
$ReportPath = Join-Path $ProjectRoot "RELATORIO-MIGRACAO-ASAAS-ORCALY.md"
$ManifestPath = Join-Path $RunRoot "manifest.txt"
$PayloadRoot = Join-Path ([System.IO.Path]::GetTempPath()) ("orcaly-asaas-migration-payload-" + [Guid]::NewGuid().ToString("N"))
$PayloadZip = Join-Path ([System.IO.Path]::GetTempPath()) ("orcaly-asaas-migration-payload-" + [Guid]::NewGuid().ToString("N") + ".zip")

$ChangedFiles = New-Object System.Collections.ArrayList
$CreatedFiles = New-Object System.Collections.ArrayList
$RestoredFiles = New-Object System.Collections.ArrayList
$BackedUpFiles = New-Object "System.Collections.Generic.HashSet[string]" ([StringComparer]::OrdinalIgnoreCase)
$UnresolvedItems = New-Object System.Collections.ArrayList
$SandboxResults = New-Object System.Collections.ArrayList
$AuditMatches = New-Object System.Collections.ArrayList
$FunctionBaseline = @{}
$BuildInitial = "NAO TESTADO"
$BuildFinal = "NAO TESTADO"
$LintInitial = "NAO TESTADO"
$LintFinal = "NAO TESTADO"
$FinalBuildPassed = $false
$ProviderAsaasStatus = "BLOQUEADO"
$ProviderMercadoPagoStatus = "PRESERVADO"
$CheckoutStatus = "BLOQUEADO"
$PixStatus = "BLOQUEADO"
$CardStatus = "BLOQUEADO"
$TokenizationStatus = "BLOQUEADA"
$SubaccountStatus = "BLOQUEADAS"
$EncryptionStatus = "BLOQUEADO"
$SplitStatus = "BLOQUEADO"
$ReceivingAccountStatus = "BLOQUEADO"
$TransactionsStatus = "BLOQUEADO"
$PayoutsStatus = "BLOQUEADOS"
$SubscriptionStatus = "BLOQUEADA"
$TrialStatus = "PRESERVADO"
$CancellationStatus = "BLOQUEADO"
$WebhookStatus = "BLOQUEADO"
$IdempotencyStatus = "BLOQUEADO"
$FinancialStatus = "BLOQUEADO"
$DatabaseStatus = "NAO APLICADA"
$MigrationCount = 0
$FunctionsPreserved = 0
$FunctionsMissing = 0
$DefaultProviderFinal = "MERCADO PAGO"

$PayloadBase64 = @'

'@

function Sanitize-LogContent {
    param([AllowNull()][string]$Content)

    if ($null -eq $Content) { return "" }

    $result = $Content
    $patterns = @(
        '(?i)(access[_-]?token|authorization|api[_-]?key|service[_-]?role|client[_-]?secret|webhook[_-]?token)\s*[:=]\s*["'']?[^"''\s,;]+',
        '(?i)Bearer\s+[A-Za-z0-9._~+/\-=]+',
        '(?i)APP_USR-[A-Za-z0-9_-]+',
        '(?i)sb_secret_[A-Za-z0-9_-]+',
        '(?i)"?(creditCard|credit_card|card|ccv|cvv|number)"?\s*:\s*"[^"]+"',
        '(?i)"?(cpfCnpj|cpf|cnpj|documento)"?\s*:\s*"[^"]+"'
    )

    foreach ($pattern in $patterns) {
        $result = [regex]::Replace($result, $pattern, '$1=[REDACTED]')
    }

    return $result
}

function Write-Log {
    param(
        [string]$Level,
        [string]$Message
    )

    $safe = Sanitize-LogContent $Message
    $line = "[{0}] [{1}] {2}" -f (Get-Date -Format "yyyy-MM-dd HH:mm:ss"), $Level, $safe

    if (-not $DryRun -and (Test-Path -LiteralPath $RunRoot)) {
        [System.IO.File]::AppendAllText(
            $ExecutionLog,
            $line + [Environment]::NewLine,
            $Utf8NoBom
        )
    }

    if ($VerboseOutput -or $Level -in @("STEP", "OK", "WARN", "ERROR")) {
        Write-Host $line
    }
}

function Write-Step {
    param([string]$Message)
    Write-Host ""
    Write-Host ("==> " + $Message) -ForegroundColor Cyan
    Write-Log "STEP" $Message
}

function Write-Success {
    param([string]$Message)
    Write-Host ("[OK] " + $Message) -ForegroundColor Green
    Write-Log "OK" $Message
}

function Write-Warning {
    param([string]$Message)
    Write-Host ("[AVISO] " + $Message) -ForegroundColor Yellow
    Write-Log "WARN" $Message
}

function Write-Failure {
    param([string]$Message)
    Write-Host ("[ERRO] " + $Message) -ForegroundColor Red
    Write-Log "ERROR" $Message
}

function Write-Info {
    param([string]$Message)
    if ($VerboseOutput) {
        Write-Host ("[INFO] " + $Message) -ForegroundColor DarkGray
    }
    Write-Log "INFO" $Message
}

function Stop-OnCriticalFailure {
    param([string]$Message)
    throw $Message
}

function Normalize-RelativePath {
    param([string]$Path)
    return (($Path -replace '/', '\') -replace '^[\\/]+', '')
}

function Get-ProjectPath {
    param([string]$RelativePath)
    return Join-Path $ProjectRoot (Normalize-RelativePath $RelativePath)
}

function Add-ChangedFile {
    param([string]$RelativePath)
    $normalized = (Normalize-RelativePath $RelativePath).Replace("\", "/")
    if (-not $ChangedFiles.Contains($normalized)) {
        [void]$ChangedFiles.Add($normalized)
    }
}

function Add-CreatedFile {
    param([string]$RelativePath)
    $normalized = (Normalize-RelativePath $RelativePath).Replace("\", "/")
    if (-not $CreatedFiles.Contains($normalized)) {
        [void]$CreatedFiles.Add($normalized)
    }
}

function Add-RestoredFile {
    param([string]$RelativePath)
    $normalized = (Normalize-RelativePath $RelativePath).Replace("\", "/")
    if (-not $RestoredFiles.Contains($normalized)) {
        [void]$RestoredFiles.Add($normalized)
    }
}

function Backup-ProjectFile {
    param([string]$RelativePath)

    $relative = Normalize-RelativePath $RelativePath
    $source = Get-ProjectPath $relative

    if (-not (Test-Path -LiteralPath $source -PathType Leaf)) { return }
    if ($BackedUpFiles.Contains($relative)) { return }

    $destination = Join-Path $BackupRoot $relative
    $parent = Split-Path -Parent $destination

    if (-not $DryRun) {
        [System.IO.Directory]::CreateDirectory($parent) | Out-Null
        Copy-Item -LiteralPath $source -Destination $destination -Force
    }

    [void]$BackedUpFiles.Add($relative)
    Write-Info ("Backup criado: " + $relative)
}

function Restore-ProjectFile {
    param([string]$RelativePath)

    $relative = Normalize-RelativePath $RelativePath
    $target = Get-ProjectPath $relative
    $backup = Join-Path $BackupRoot $relative

    if (Test-Path -LiteralPath $backup -PathType Leaf) {
        $parent = Split-Path -Parent $target
        [System.IO.Directory]::CreateDirectory($parent) | Out-Null
        Copy-Item -LiteralPath $backup -Destination $target -Force
        Add-RestoredFile $relative
        return
    }

    $slash = $relative.Replace("\", "/")
    if ($CreatedFiles.Contains($slash) -and (Test-Path -LiteralPath $target)) {
        Remove-Item -LiteralPath $target -Force
        Add-RestoredFile $relative
    }
}

function Restore-AllChanges {
    Write-Warning "Restaurando arquivos porque o build final falhou."

    $all = @((@($ChangedFiles) + @($CreatedFiles)) | Sort-Object -Unique)
    [array]::Reverse($all)

    foreach ($relative in $all) {
        Restore-ProjectFile $relative
    }
}

function Write-Utf8NoBom {
    param(
        [string]$Path,
        [AllowEmptyString()][string]$Content
    )

    $parent = Split-Path -Parent $Path
    if ($parent) {
        [System.IO.Directory]::CreateDirectory($parent) | Out-Null
    }

    [System.IO.File]::WriteAllText($Path, $Content, $Utf8NoBom)
}

function Update-ProjectFile {
    param(
        [string]$RelativePath,
        [AllowEmptyString()][string]$Content
    )

    $relative = Normalize-RelativePath $RelativePath
    $target = Get-ProjectPath $relative
    $exists = Test-Path -LiteralPath $target -PathType Leaf
    $current = if ($exists) {
        [System.IO.File]::ReadAllText($target)
    } else {
        $null
    }

    $normalizedContent = $Content.Replace("`r`n", "`n")

    if ($exists -and $current.Replace("`r`n", "`n") -ceq $normalizedContent) {
        Write-Info ("Sem alteracao: " + $relative)
        return $false
    }

    if ($DryRun) {
        Write-Host ("[DRYRUN] " + $(if ($exists) { "Atualizaria " } else { "Criaria " }) + $relative) -ForegroundColor Magenta
        return $true
    }

    if ($exists) {
        Backup-ProjectFile $relative
        Add-ChangedFile $relative
    } else {
        Add-CreatedFile $relative
    }

    $parent = Split-Path -Parent $target
    [System.IO.Directory]::CreateDirectory($parent) | Out-Null
    Write-Utf8NoBom $target $normalizedContent
    Write-Success ($(if ($exists) { "Atualizado: " } else { "Criado: " }) + $relative)
    return $true
}

function Write-JsonFile {
    param(
        [string]$Path,
        [object]$Value,
        [int]$Depth = 12
    )

    $json = $Value | ConvertTo-Json -Depth $Depth
    Write-Utf8NoBom $Path $json
}

function Test-ProjectStructure {
    $required = @("package.json", "app", "components", "lib")

    foreach ($item in $required) {
        $path = Join-Path $ProjectRoot $item
        if (-not (Test-Path -LiteralPath $path)) {
            Stop-OnCriticalFailure ("Execute o script na raiz do projeto. Ausente: " + $item)
        }
    }

    if (Test-Path -LiteralPath (Join-Path $ProjectRoot "middleware.ts")) {
        Write-Warning "middleware.ts ja existe no projeto. O patcher nao ira altera-lo."
    }

    Write-Success "Estrutura do projeto validada."
}

function Test-PowerShellSyntax {
    param([string]$Path)

    $tokens = $null
    $errors = $null
    [System.Management.Automation.Language.Parser]::ParseFile(
        $Path,
        [ref]$tokens,
        [ref]$errors
    ) | Out-Null

    if ($errors -and $errors.Count -gt 0) {
        foreach ($error in $errors) {
            Write-Failure (
                "Sintaxe linha {0}, coluna {1}: {2}" -f
                $error.Extent.StartLineNumber,
                $error.Extent.StartColumnNumber,
                $error.Message
            )
        }
        return $false
    }

    return $true
}

function Test-RequiredFunctions {
    $required = @(
        "Write-Step",
        "Write-Success",
        "Write-Warning",
        "Write-Failure",
        "Write-Info",
        "Backup-ProjectFile",
        "Restore-ProjectFile",
        "Write-Utf8NoBom",
        "Update-ProjectFile",
        "Add-ChangedFile",
        "Add-CreatedFile",
        "Add-RestoredFile",
        "Invoke-NpmCommand",
        "Invoke-CommandWithTimeout",
        "Invoke-NodeScript",
        "Test-PowerShellSyntax",
        "Test-ProjectStructure",
        "Test-RequiredFunctions",
        "Compare-FunctionInventory",
        "Sanitize-LogContent",
        "Stop-OnCriticalFailure",
        "Write-FinalReport"
    )

    $missing = @()
    foreach ($name in $required) {
        if (-not (Get-Command -Name $name -CommandType Function -ErrorAction SilentlyContinue)) {
            $missing += $name
        }
    }

    if ($missing.Count -gt 0) {
        Stop-OnCriticalFailure ("Helpers ausentes: " + ($missing -join ", "))
    }

    Write-Success "Helpers obrigatorios validados."
}

function Get-FunctionInventory {
    param([AllowNull()][string]$Content)

    if (-not $Content) { return @() }

    $names = New-Object System.Collections.ArrayList
    $patterns = @(
        '(?m)\b(?:export\s+)?(?:async\s+)?function\s+([A-Za-z_$][A-Za-z0-9_$]*)',
        '(?m)\b(?:const|let)\s+([A-Za-z_$][A-Za-z0-9_$]*)\s*=\s*(?:async\s*)?\(',
        '(?m)\b(?:const|let)\s+([A-Za-z_$][A-Za-z0-9_$]*)\s*=\s*(?:async\s*)?[A-Za-z_$][A-Za-z0-9_$]*\s*=>'
    )

    foreach ($pattern in $patterns) {
        foreach ($match in [regex]::Matches($Content, $pattern)) {
            $name = $match.Groups[1].Value
            if ($name -and -not $names.Contains($name)) {
                [void]$names.Add($name)
            }
        }
    }

    return @($names)
}

function Compare-FunctionInventory {
    param(
        [AllowNull()][string]$Before,
        [AllowNull()][string]$After
    )

    $beforeNames = @(Get-FunctionInventory $Before)
    $afterNames = @(Get-FunctionInventory $After)
    $missing = @($beforeNames | Where-Object { $afterNames -notcontains $_ })

    return [pscustomobject]@{
        Before = $beforeNames
        After = $afterNames
        Missing = $missing
        Preserved = @($beforeNames | Where-Object { $afterNames -contains $_ })
    }
}

function Invoke-NpmCommand {
    param(
        [string]$Label,
        [string[]]$Arguments,
        [string]$LogPath
    )

    Write-Step ("Executando npm.cmd " + ($Arguments -join " "))
    $started = Get-Date
    $oldPreference = $ErrorActionPreference
    $ErrorActionPreference = "Continue"

    try {
        & npm.cmd @Arguments 2>&1 |
            ForEach-Object { Sanitize-LogContent ([string]$_) } |
            Tee-Object -FilePath $LogPath |
            Out-Host
        $exitCode = $LASTEXITCODE
    } finally {
        $ErrorActionPreference = $oldPreference
    }

    $duration = [math]::Round(((Get-Date) - $started).TotalSeconds, 2)
    $passed = $exitCode -eq 0

    if ($passed) {
        Write-Success ($Label + " passou em " + $duration + "s.")
    } else {
        Write-Warning ($Label + " falhou com codigo " + $exitCode + ".")
    }

    return [pscustomobject]@{
        Label = $Label
        Passed = $passed
        ExitCode = $exitCode
        DurationSeconds = $duration
        Log = $LogPath
    }
}

function Invoke-CommandWithTimeout {
    param(
        [string]$FilePath,
        [string[]]$Arguments,
        [int]$TimeoutSeconds,
        [string]$Label
    )

    $stdout = Join-Path $RunRoot ($Label + "-stdout.log")
    $stderr = Join-Path $RunRoot ($Label + "-stderr.log")
    $argumentLine = ($Arguments | ForEach-Object {
        if ($_ -match '\s') { '"' + $_.Replace('"', '\"') + '"' } else { $_ }
    }) -join " "

    $process = Start-Process `
        -FilePath $FilePath `
        -ArgumentList $argumentLine `
        -WorkingDirectory $ProjectRoot `
        -NoNewWindow `
        -PassThru `
        -RedirectStandardOutput $stdout `
        -RedirectStandardError $stderr

    $completed = $process.WaitForExit($TimeoutSeconds * 1000)

    if (-not $completed) {
        try { $process.Kill() } catch {}
        return [pscustomobject]@{
            Passed = $false
            ExitCode = -1
            TimedOut = $true
            StdOut = if (Test-Path $stdout) { Sanitize-LogContent ([IO.File]::ReadAllText($stdout)) } else { "" }
            StdErr = if (Test-Path $stderr) { Sanitize-LogContent ([IO.File]::ReadAllText($stderr)) } else { "" }
        }
    }

    $process.WaitForExit()
    return [pscustomobject]@{
        Passed = $process.ExitCode -eq 0
        ExitCode = $process.ExitCode
        TimedOut = $false
        StdOut = if (Test-Path $stdout) { Sanitize-LogContent ([IO.File]::ReadAllText($stdout)) } else { "" }
        StdErr = if (Test-Path $stderr) { Sanitize-LogContent ([IO.File]::ReadAllText($stderr)) } else { "" }
    }
}

function Invoke-NodeScript {
    param(
        [string]$Label,
        [string]$Content,
        [int]$TimeoutSeconds = 45
    )

    $scriptPath = Join-Path $RunRoot ($Label + ".mjs")
    Write-Utf8NoBom $scriptPath $Content
    return Invoke-CommandWithTimeout `
        -FilePath "node.exe" `
        -Arguments @($scriptPath) `
        -TimeoutSeconds $TimeoutSeconds `
        -Label $Label
}

function Get-PackageScripts {
    try {
        $package = Get-Content -LiteralPath (Join-Path $ProjectRoot "package.json") -Raw | ConvertFrom-Json
        return @($package.scripts.PSObject.Properties.Name)
    } catch {
        return @()
    }
}

function Expand-Payload {
    [System.IO.Directory]::CreateDirectory($PayloadRoot) | Out-Null
    [System.IO.File]::WriteAllBytes(
        $PayloadZip,
        [Convert]::FromBase64String($PayloadBase64.Trim())
    )

    Add-Type -AssemblyName System.IO.Compression.FileSystem
    [System.IO.Compression.ZipFile]::ExtractToDirectory($PayloadZip, $PayloadRoot)
}

function Invoke-Audit {
    Write-Step "Fase 0 - auditando codigo, checkout, assinatura e providers"

    $roots = @(
        "app",
        "components",
        "lib",
        "supabase"
    )

    $patterns = @(
        "MercadoPago",
        "mercado-pago",
        "checkout/preferences",
        "preapproval",
        "provider",
        "walletId",
        "Asaas",
        "split",
        "PIX",
        "CREDIT_CARD",
        "company_id",
        "external_reference",
        "idempotency",
        "webhook",
        "trial_used_at",
        "marketplace_fee",
        "plan_payments",
        "marketplace_payments",
        "order_payments",
        "subscription_events"
    )

    $allowedExtensions = @(
        ".ts",
        ".tsx",
        ".js",
        ".jsx",
        ".sql",
        ".json"
    )

    $files = @()

    foreach ($root in $roots) {
        $absolute = Join-Path $ProjectRoot $root

        if (-not (Test-Path -LiteralPath $absolute -PathType Container)) {
            continue
        }

        $candidates = @(
            Get-ChildItem `
                -LiteralPath $absolute `
                -Recurse `
                -File `
                -ErrorAction SilentlyContinue
        )

        foreach ($candidate in $candidates) {
            if (
                $candidate.FullName -match
                '\\node_modules\\|\\.next\\|\\.git\\|\\.orcaly-backups\\|\\.orcaly-migration\\'
            ) {
                continue
            }

            if ($allowedExtensions -notcontains $candidate.Extension) {
                continue
            }

            $relative = $candidate.FullName.Substring($ProjectRoot.Length)
            $relative = $relative -replace '^[\\/]+', ''
            $relative = $relative -replace '\\', '/'

            $content = ""

            try {
                $content = [System.IO.File]::ReadAllText(
                    $candidate.FullName
                )
            } catch {
                if ($VerboseOutput) {
                    Write-Warning ("Nao foi possivel ler: " + $relative)
                }
                continue
            }

            $contentLower = $content.ToLowerInvariant()
            $hits = @()

            foreach ($pattern in $patterns) {
                $patternText = [string]$pattern

                if (
                    $contentLower.Contains(
                        $patternText.ToLowerInvariant()
                    )
                ) {
                    $hits += $patternText
                }
            }

            if (
                $hits.Count -gt 0 -or
                $relative -match
                '(?i)payment|pagamento|checkout|assinatura|subscription|mercado|asaas|financeiro'
            ) {
                $files += [pscustomobject][ordered]@{
                    path = [string]$relative
                    matches = @($hits | Sort-Object -Unique)
                    size = [int64]$candidate.Length
                }
            }
        }
    }

    $migrationFiles = @(
        Get-ChildItem `
            -LiteralPath (Join-Path $ProjectRoot "supabase\migrations") `
            -Filter "*.sql" `
            -File `
            -ErrorAction SilentlyContinue |
            Sort-Object Name |
            ForEach-Object {
                [pscustomobject][ordered]@{
                    name = $_.Name
                    size = [int64]$_.Length
                }
            }
    )

    $knownTables = @(
        "companies",
        "orders",
        "order_items",
        "order_payments",
        "plan_payments",
        "marketplace_payment_settings",
        "marketplace_payments",
        "marketplace_commissions",
        "marketplace_commission_rules",
        "marketplace_oauth_states",
        "subscription_events",
        "financial_transactions",
        "payment_methods",
        "deliveries",
        "delivery_zones",
        "business_hours",
        "marketplace_coupons"
    )

    $schemaHints = @()

    foreach ($table in $knownTables) {
        $matches = @(
            $files |
                Where-Object {
                    $_.path -match '(?i)\.sql$'
                } |
                ForEach-Object {
                    $source = Get-ProjectPath $_.path
                    $text = ""
                    try {
                        $text = [System.IO.File]::ReadAllText($source)
                    } catch {}

                    if (
                        $text.ToLowerInvariant().Contains(
                            $table.ToLowerInvariant()
                        )
                    ) {
                        $_.path
                    }
                }
        )

        $schemaHints += [pscustomobject][ordered]@{
            table = $table
            referencedInMigrations = @($matches | Sort-Object -Unique)
            liveSchemaVerified = $false
        }
    }

    $audit = [ordered]@{
        generatedAt = (Get-Date).ToString("o")
        project = "Orcaly"
        projectRoot = [string]$ProjectRoot
        phase = [string]$Phase
        files = @($files)
        migrations = $migrationFiles
        existingMercadoPagoRoutes = @(
            $files |
                Where-Object {
                    $_.path -match '(?i)mercado-pago'
                } |
                ForEach-Object {
                    [string]$_.path
                }
        )
        existingPaymentFiles = @(
            $files |
                Where-Object {
                    $_.path -match '(?i)payment|pagamento|checkout'
                } |
                ForEach-Object {
                    [string]$_.path
                }
        )
        schemaHints = $schemaHints
        notes = @(
            "A auditoria nao le arquivos .env.",
            "O schema ao vivo nao foi presumido.",
            "A migration usa verificacoes aditivas e tabelas equivalentes existentes.",
            "Mercado Pago permanece preservado como fallback."
        )
    }

    if (-not $DryRun) {
        Write-JsonFile $AuditPath $audit 16
        Write-JsonFile $SchemaPath $schemaHints 10
    }

    Write-Success (
        "Auditoria concluida: " +
        @($files).Count +
        " arquivos relacionados."
    )

    return $audit
}

function Get-PayloadEntries {
    if (-not (Test-Path -LiteralPath $PayloadRoot)) {
        Expand-Payload
    }

    return @(
        Get-ChildItem -LiteralPath $PayloadRoot -Recurse -File |
            ForEach-Object {
                (($_.FullName.Substring($PayloadRoot.Length) -replace '^[\\/]+', '') -replace '\\', '/')
            } |
            Sort-Object
    )
}

function Install-LegacyPageWrapper {
    param(
        [string]$PagePath,
        [string]$LegacyPath,
        [string]$SpecialPayloadPath,
        [string]$Marker
    )

    $page = Get-ProjectPath $PagePath
    $legacy = Get-ProjectPath $LegacyPath
    $special = Join-Path $PayloadRoot (Normalize-RelativePath $SpecialPayloadPath)
    $specialContent = [IO.File]::ReadAllText($special)

    if (Test-Path -LiteralPath $page -PathType Leaf) {
        $current = [IO.File]::ReadAllText($page)

        if ($current.ToLowerInvariant().Contains(([string]$Marker).ToLowerInvariant())) {
            Write-Info ("Wrapper ja instalado: " + $PagePath)
            return
        }

        $FunctionBaseline[$PagePath] = @(Get-FunctionInventory $current)

        if (-not (Test-Path -LiteralPath $legacy -PathType Leaf)) {
            [void](Update-ProjectFile $LegacyPath $current)
        }

        [void](Update-ProjectFile $PagePath $specialContent)
        return
    }

    if (-not (Test-Path -LiteralPath $legacy -PathType Leaf)) {
        $fallbackPage = @'
// ORCALY_ASAAS_PLATFORM_V1
export default function LegacyPageFallback() {
  return null;
}
'@
        [void](Update-ProjectFile $LegacyPath $fallbackPage)
    }

    [void](Update-ProjectFile $PagePath $specialContent)
}

function Install-LegacyRouteWrapper {
    param(
        [string]$RoutePath,
        [string]$LegacyPath,
        [string]$SpecialPayloadPath,
        [string]$Marker
    )

    $route = Get-ProjectPath $RoutePath
    $legacy = Get-ProjectPath $LegacyPath
    $special = Join-Path $PayloadRoot (Normalize-RelativePath $SpecialPayloadPath)
    $specialContent = [IO.File]::ReadAllText($special)

    if (Test-Path -LiteralPath $route -PathType Leaf) {
        $current = [IO.File]::ReadAllText($route)

        if ($current.ToLowerInvariant().Contains(([string]$Marker).ToLowerInvariant())) {
            Write-Info ("Wrapper ja instalado: " + $RoutePath)
            return
        }

        $FunctionBaseline[$RoutePath] = @(Get-FunctionInventory $current)

        if (-not (Test-Path -LiteralPath $legacy -PathType Leaf)) {
            [void](Update-ProjectFile $LegacyPath $current)
        }

        [void](Update-ProjectFile $RoutePath $specialContent)
        return
    }

    if (-not (Test-Path -LiteralPath $legacy -PathType Leaf)) {
        $fallbackRoute = @'
// ORCALY_ASAAS_PLATFORM_V1
import { NextResponse } from "next/server";

export async function POST() {
  return NextResponse.json(
    { error: "Provider legado nao configurado." },
    { status: 501 },
  );
}
'@
        [void](Update-ProjectFile $LegacyPath $fallbackRoute)
    }

    [void](Update-ProjectFile $RoutePath $specialContent)
}

function Test-PhaseIncludes {
    param([string]$Name)

    if ($Phase -eq "all") {
        return $true
    }

    return $Phase -eq $Name
}

function Should-ApplyPayloadFile {
    param([string]$RelativePath)

    $relative = $RelativePath.Replace("\", "/")

    if ($Phase -eq "all") {
        return $true
    }

    if ($Phase -eq "infrastructure") {
        return (
            $relative -match '^lib/payments/' -or
            $relative -match '^lib/plans/' -or
            $relative -match '^(CONFIGURACAO|PLANO-ROLLBACK)'
        )
    }

    if ($Phase -eq "database") {
        return (
            $relative -match '^supabase/migrations/' -or
            $relative -eq 'CONFIGURACAO-MIGRACAO-ASAAS-ORCALY.md' -or
            $relative -eq 'PLANO-ROLLBACK-MIGRACAO-ASAAS-ORCALY.md'
        )
    }

    if ($Phase -eq "backend") {
        return (
            $relative -match '^lib/payments/' -or
            $relative -match '^lib/plans/' -or
            $relative -match '^app/api/'
        )
    }

    if ($Phase -eq "ui") {
        return (
            $relative -match '^components/' -or
            $relative -match '^app/checkout/' -or
            $relative -match '^app/admin/' -or
            $relative -match '^CHECKLIST-' -or
            $relative -match '^CONFIGURACAO-' -or
            $relative -match '^PLANO-ROLLBACK-'
        )
    }

    return $false
}

function Apply-Payload {
    Write-Step ("Aplicando fase: " + $Phase)

    foreach ($relative in Get-PayloadEntries) {
        if ($relative.StartsWith("__special__/")) {
            continue
        }

        if (-not (Should-ApplyPayloadFile $relative)) {
            continue
        }

        $source = Join-Path $PayloadRoot (Normalize-RelativePath $relative)
        $content = [System.IO.File]::ReadAllText($source)

        if (
            $relative -eq
            "supabase/migrations/20260723_migracao_gradual_asaas_orcaly.sql"
        ) {
            $script:MigrationCount = 1

            if (-not $DryRun) {
                Write-Utf8NoBom $DatabasePlanPath $content
            }
        }

        [void](Update-ProjectFile $relative $content)
    }

    if ($Phase -in @("ui", "all")) {
        Install-LegacyPageWrapper `
            -PagePath "app/painel/pagamentos/page.tsx" `
            -LegacyPath "app/painel/pagamentos/PagamentosLegacy.tsx" `
            -SpecialPayloadPath "__special__/payments-page.tsx" `
            -Marker "PaymentsHub"

        Install-LegacyPageWrapper `
            -PagePath "app/painel/assinatura/page.tsx" `
            -LegacyPath "app/painel/assinatura/AssinaturaLegacy.tsx" `
            -SpecialPayloadPath "__special__/subscription-page.tsx" `
            -Marker "AsaasSubscriptionPayment"
    }

    if ($Phase -in @("backend", "all")) {
        Install-LegacyRouteWrapper `
            -RoutePath "app/api/checkout/plano/route.ts" `
            -LegacyPath "app/api/checkout/plano/route.mercado-pago.ts" `
            -SpecialPayloadPath "__special__/checkout-plan-wrapper.ts" `
            -Marker "asaasPost"

        Install-LegacyRouteWrapper `
            -RoutePath "app/api/assinatura/cancelar/route.ts" `
            -LegacyPath "app/api/assinatura/cancelar/route.mercado-pago.ts" `
            -SpecialPayloadPath "__special__/cancel-wrapper.ts" `
            -Marker "asaasPost"
    }
}

