    $script:CheckoutStatus = if ($results.Checkout) { "IMPLEMENTADO" } else { "FALHOU" }
    $script:EncryptionStatus = if ($results.Encryption) { "IMPLEMENTADA" } else { "FALHOU" }
    $script:SplitStatus = if ($results.Split) { "IMPLEMENTADO" } else { "FALHOU" }
    $script:WebhookStatus = if ($results.Webhook) { "IMPLEMENTADO" } else { "FALHOU" }
    $script:SubscriptionStatus = if ($results.Subscription) { "IMPLEMENTADA" } else { "FALHOU" }
    $script:ReceivingAccountStatus = if ($results.PaymentsPage) { "IMPLEMENTADA" } else { "FALHOU" }
    $script:TransactionsStatus = if ($results.PaymentsPage) { "IMPLEMENTADAS" } else { "FALHOU" }
    $script:PayoutsStatus = if ($results.PaymentsPage) { "IMPLEMENTADOS" } else { "FALHOU" }
    $script:PixStatus = if ($results.Checkout) { "IMPLEMENTADO" } else { "BLOQUEADO" }
    $script:CardStatus = if ($results.Checkout) { "IMPLEMENTADO" } else { "BLOQUEADO" }
    $script:IdempotencyStatus = if (
        (Get-Content -LiteralPath (Get-ProjectPath "lib/payments/checkout-service.ts") -Raw) -match "idempotency"
    ) { "IMPLEMENTADA" } else { "FALHOU" }
    $script:FinancialStatus = if (
        Test-Path -LiteralPath (Get-ProjectPath "lib/payments/financial-integration.ts")
    ) { "INTEGRADO" } else { "FALHOU" }

    $capabilities = @{
        CardEnabled = [string]::Equals(
