function Compare-ProtectedFunctions {
    foreach ($entry in $FunctionBaseline.GetEnumerator()) {
        $relative = [string]$entry.Key
        $before = @($entry.Value)
        $legacyPath = switch -Regex ($relative) {
            '^app/painel/pagamentos/page\.tsx$' { "app/painel/pagamentos/PagamentosLegacy.tsx"; break }
            '^app/painel/assinatura/page\.tsx$' { "app/painel/assinatura/AssinaturaLegacy.tsx"; break }
            '^app/api/checkout/plano/route\.ts$' { "app/api/checkout/plano/route.mercado-pago.ts"; break }
            '^app/api/assinatura/cancelar/route\.ts$' { "app/api/assinatura/cancelar/route.mercado-pago.ts"; break }
            default { $relative }
        }

        $legacyFile = Get-ProjectPath $legacyPath
        $after = if (Test-Path -LiteralPath $legacyFile) {
            [IO.File]::ReadAllText($legacyFile)
        } else {
            ""
        }

        $comparison = Compare-FunctionInventory ($before -join "`n") $after
        # The baseline is an inventory, so direct name comparison is clearer here.
        $afterNames = @(Get-FunctionInventory $after)
        $missing = @($before | Where-Object { $afterNames -notcontains $_ })
        $preserved = @($before | Where-Object { $afterNames -contains $_ })
        $script:FunctionsPreserved += $preserved.Count
        $script:FunctionsMissing += $missing.Count

        if ($missing.Count -gt 0) {
            [void]$UnresolvedItems.Add([pscustomobject]@{
                area = "Regressao"
                item = $relative
                status = "FUNCOES AUSENTES"
                details = @($missing)
            })
        }
    }

    if ($FunctionsMissing -gt 0) {
        Stop-OnCriticalFailure (
            "Funcoes protegidas desapareceram durante a consolidacao: " +
            $FunctionsMissing
        )
    }
}

