function Invoke-DatabaseMigration {
    if (-not $ApplyDatabaseMigration) {
        $script:DatabaseStatus = "NAO APLICADA"
        Write-Warning "Migration gerada. Use -ApplyDatabaseMigration para aplicar."
        return
    }

    $migration = Get-ProjectPath (
        "supabase/migrations/" +
        "20260723_migracao_gradual_asaas_orcaly.sql"
    )

    if (-not (Test-Path -LiteralPath $migration -PathType Leaf)) {
        $script:DatabaseStatus = "FALHOU"
        Stop-OnCriticalFailure "A migration Asaas nao foi encontrada."
    }

    $databaseUrl = [string]$env:SUPABASE_DB_URL

    if ([string]::IsNullOrWhiteSpace($databaseUrl)) {
        $databaseUrl = [string]$env:DATABASE_URL
    }

    if ([string]::IsNullOrWhiteSpace($databaseUrl)) {
        $script:DatabaseStatus = "NAO APLICADA"
        [void]$UnresolvedItems.Add([pscustomobject]@{
            area = "Banco"
            item = "Aplicacao da migration"
            status = "BLOQUEADO"
            detail = "SUPABASE_DB_URL ou DATABASE_URL nao esta disponivel."
        })
        Write-Warning "Migration nao aplicada: conexao de banco ausente."
        return
    }

    $psql = Get-Command psql.exe -ErrorAction SilentlyContinue

    if (-not $psql) {
        $psql = Get-Command psql -ErrorAction SilentlyContinue
    }

    if (-not $psql) {
        $script:DatabaseStatus = "NAO APLICADA"
        [void]$UnresolvedItems.Add([pscustomobject]@{
            area = "Banco"
            item = "Aplicacao da migration"
            status = "BLOQUEADO"
            detail = "psql nao foi encontrado. Aplique a migration no SQL Editor do Supabase."
        })
        Write-Warning "psql nao encontrado. Aplique a migration manualmente."
        return
    }

    Write-Step "Aplicando migration com psql"

    $oldPreference = $ErrorActionPreference
    $ErrorActionPreference = "Continue"

    try {
        & $psql.Source `
            "--dbname=$databaseUrl" `
            "-v" `
            "ON_ERROR_STOP=1" `
            "-f" `
            $migration 2>&1 |
            ForEach-Object {
                Sanitize-LogContent ([string]$_)
            } |
            Tee-Object -FilePath (Join-Path $RunRoot "database-apply.log") |
            Out-Host

        $exitCode = $LASTEXITCODE
    } finally {
        $ErrorActionPreference = $oldPreference
    }

    if ($exitCode -ne 0) {
        $script:DatabaseStatus = "FALHOU"
        Stop-OnCriticalFailure (
            "A migration falhou com codigo " +
            $exitCode +
            ". Nenhum rollback destrutivo foi executado."
        )
    }

    $script:DatabaseStatus = "APLICADA"
    Write-Success "Migration aplicada."
}

