function Invoke-Rollback {
    Write-Step "Executando rollback de codigo"

    $runsRoot = Join-Path $ProjectRoot ".orcaly-migration"

    if (-not (Test-Path -LiteralPath $runsRoot -PathType Container)) {
        Stop-OnCriticalFailure "Nenhuma execucao anterior foi encontrada."
    }

    $previousRun = Get-ChildItem `
        -LiteralPath $runsRoot `
        -Directory `
        -ErrorAction SilentlyContinue |
        Where-Object {
            $_.Name -like "migracao-asaas-*" -and
            $_.FullName -ne $RunRoot -and
            (Test-Path -LiteralPath (Join-Path $_.FullName "changed-files.json"))
        } |
        Sort-Object Name -Descending |
        Select-Object -First 1

    if (-not $previousRun) {
        Stop-OnCriticalFailure "Nao foi encontrado manifesto para rollback."
    }

    $suffix = $previousRun.Name.Substring("migracao-asaas-".Length)
    $previousBackup = Join-Path `
        (Join-Path $ProjectRoot ".orcaly-backups") `
        ("migracao-asaas-" + $suffix)

    if (-not (Test-Path -LiteralPath $previousBackup -PathType Container)) {
        Stop-OnCriticalFailure (
            "Backup correspondente nao encontrado: " +
            $previousBackup
        )
    }

    $changed = @()
    $created = @()

    try {
        $changed = @(
            Get-Content `
                -LiteralPath (Join-Path $previousRun.FullName "changed-files.json") `
                -Raw |
                ConvertFrom-Json
        )
    } catch {}

    try {
        $created = @(
            Get-Content `
                -LiteralPath (Join-Path $previousRun.FullName "created-files.json") `
                -Raw |
                ConvertFrom-Json
        )
    } catch {}

    foreach ($relative in $changed) {
        $normalized = Normalize-RelativePath ([string]$relative)
        $source = Join-Path $previousBackup $normalized
        $target = Get-ProjectPath $normalized

        if (Test-Path -LiteralPath $source -PathType Leaf) {
            $parent = Split-Path -Parent $target
            [System.IO.Directory]::CreateDirectory($parent) | Out-Null
            Copy-Item -LiteralPath $source -Destination $target -Force
            Add-RestoredFile $normalized
        }
    }

    foreach ($relative in $created) {
        $normalized = Normalize-RelativePath ([string]$relative)
        $target = Get-ProjectPath $normalized

        if (
            (Test-Path -LiteralPath $target -PathType Leaf) -and
            $normalized -notmatch '^supabase\\migrations\\'
        ) {
            Remove-Item -LiteralPath $target -Force
            Add-RestoredFile $normalized
        }
    }

    $script:DefaultProviderFinal = "MERCADO PAGO"
    $script:ProviderMercadoPagoStatus = "PRESERVADO"
    Write-Success "Rollback de codigo concluido."
    Write-Warning (
        "O banco nao foi revertido. Desative as flags e volte a empresa piloto " +
        "para Mercado Pago."
    )
}

