    Write-JsonFile $CreatedPath @($CreatedFiles | Sort-Object -Unique)
    Write-JsonFile $RestoredPath @($RestoredFiles | Sort-Object -Unique)
    Write-JsonFile $SandboxPath @($SandboxResults)
    Write-JsonFile $UnresolvedPath @($UnresolvedItems)

    $lines = @(
        "Changed files:",
        ($ChangedFiles | Sort-Object -Unique),
        "",
        "Created files:",
        ($CreatedFiles | Sort-Object -Unique),
        "",
        "Restored files:",
        ($RestoredFiles | Sort-Object -Unique)
    )
    Write-Utf8NoBom $ManifestPath ($lines -join [Environment]::NewLine)
}

function Write-FinalReport {
    $sandboxPassed = @(
        $SandboxResults |
            Where-Object {
                $_.status -eq "PASSOU"
            }
    ).Count

    $sandboxFailed = @(
        $SandboxResults |
            Where-Object {
                $_.status -eq "FALHOU"
            }
    ).Count

    $sandboxBlocked = @(
        $SandboxResults |
            Where-Object {
                $_.status -eq "BLOQUEADO"
            }
    ).Count

    $report = @"
# Relatorio da migracao Mercado Pago para Asaas

## Resumo

A migracao foi preparada de forma gradual e reversivel. Mercado Pago permanece preservado e nenhuma ativacao de producao foi executada.

## Execucao

- Fase: $Phase
- DryRun: $DryRun
- Provider padrao final: $DefaultProviderFinal
- Banco: $DatabaseStatus
- Build inicial: $BuildInitial
- Lint inicial: $LintInitial
- Build final: $BuildFinal
- Lint final: $LintFinal

## Providers

- Mercado Pago: $ProviderMercadoPagoStatus
- Asaas: $ProviderAsaasStatus
- Subcontas: $SubaccountStatus
- Criptografia: $EncryptionStatus
- Checkout: $CheckoutStatus
- Pix: $PixStatus
- Cartao: $CardStatus
- Tokenizacao: $TokenizationStatus
- Split: $SplitStatus
- Webhook: $WebhookStatus
- Idempotencia: $IdempotencyStatus
- Financeiro: $FinancialStatus
- Assinatura: $SubscriptionStatus
- Trial: $TrialStatus
- Cancelamento: $CancellationStatus

## Comissoes

| Plano | Percentual |
|---|---:|
| Essencial | 3% |
| Profissional | 2% |
| Premium | 1% |

A comissao e resolvida no servidor. O split percentual do Asaas usa o valor liquido da cobranca. Valores exatos de tarifa e liquido somente devem ser exibidos como confirmados apos retorno do provider.

## Banco

A migration reutiliza as tabelas existentes:

- marketplace_payment_settings
- marketplace_payments
- marketplace_commissions
- order_payments
- plan_payments
- subscription_events

Novas tabelas sao criadas apenas quando nao ha equivalente direto:

- payment_webhook_events
- payment_payouts
- provider_customers

O patcher nao executa DROP, TRUNCATE ou exclusao em massa.

## Seguranca

- AES-256-GCM para credenciais da subconta.
- API key e token de webhook nunca sao enviados ao frontend.
- Numero do cartao e CVV nao sao persistidos.
- remoteIp deve vir do cliente.
- Webhook valida asaas-access-token.
- Eventos sao idempotentes.
- Producao exige aprovacao explicita.

## Sandbox

- Passaram: $sandboxPassed
- Falharam: $sandboxFailed
- Bloqueados: $sandboxBlocked
- Nenhuma cobranca real foi criada pelo patcher.

## Arquivos

- Alterados: $($ChangedFiles.Count)
- Criados: $($CreatedFiles.Count)
- Restaurados: $($RestoredFiles.Count)
- Backups: $BackupRoot
- Logs: $RunRoot

## Producao

**NAO LIBERADA.** A ativacao deve ocorrer por empresa piloto, depois de sandbox, onboarding, webhook, Pix, split, assinatura e conciliacao.
"@

    [void](Update-ProjectFile "RELATORIO-MIGRACAO-ASAAS-ORCALY.md" $report)
}

function Show-FinalSummary {
    $sandboxStatus = if (
        @(
            $SandboxResults |
                Where-Object {
                    $_.status -eq "FALHOU"
                }
        ).Count -gt 0
    ) {
        "FALHOU"
    } elseif (
        @(
            $SandboxResults |
                Where-Object {
                    $_.status -eq "PASSOU"
                }
        ).Count -gt 0
    ) {
        "PASSOU"
    } else {
        "BLOQUEADO"
    }

    Write-Host ""
    Write-Host "========================================" -ForegroundColor Cyan
    Write-Host "ORCALY - MIGRACAO MERCADO PAGO -> ASAAS" -ForegroundColor Cyan
    Write-Host "========================================" -ForegroundColor Cyan
    Write-Host ""
    Write-Host ("Fase executada: " + $Phase)
    Write-Host ("DryRun: " + $(if ($DryRun) { "SIM" } else { "NAO" }))
    Write-Host ""
    Write-Host "Mercado Pago:"
    Write-Host $ProviderMercadoPagoStatus
    Write-Host ""
    Write-Host "Provider Asaas:"
    Write-Host $ProviderAsaasStatus
    Write-Host ""
    Write-Host "Banco:"
    Write-Host $DatabaseStatus
    Write-Host ""
    Write-Host ("Checkout proprio: " + $CheckoutStatus)
    Write-Host ("Pix: " + $PixStatus)
    Write-Host ("Cartao: " + $CardStatus)
    Write-Host ("Subcontas: " + $SubaccountStatus)
    Write-Host ("Criptografia: " + $EncryptionStatus)
    Write-Host ("Split: " + $SplitStatus)
    Write-Host ""
    Write-Host "Comissoes:"
    Write-Host "Essencial 3%"
    Write-Host "Profissional 2%"
    Write-Host "Premium 1%"
    Write-Host ""
    Write-Host ("Assinatura: " + $SubscriptionStatus)
    Write-Host ("Webhook: " + $WebhookStatus)
    Write-Host ("Idempotencia: " + $IdempotencyStatus)
    Write-Host ("Financeiro: " + $FinancialStatus)
    Write-Host ""
    Write-Host ("Paginas modernizadas: 3")
    Write-Host (
        "Componentes criados: " +
        @(
            $CreatedFiles |
                Where-Object {
                    $_ -match '^components/'
                }
        ).Count
    )
    Write-Host ("Arquivos alterados: " + $ChangedFiles.Count)
    Write-Host ("Arquivos restaurados: " + $RestoredFiles.Count)
    Write-Host ""
    Write-Host ("Build inicial: " + $BuildInitial)
    Write-Host ("Lint inicial: " + $LintInitial)
    Write-Host ("Build final: " + $BuildFinal)
    Write-Host ("Lint final: " + $LintFinal)
    Write-Host ("Testes sandbox: " + $sandboxStatus)
    Write-Host ""
    Write-Host ("Provider padrao final: " + $DefaultProviderFinal)
    Write-Host "Producao Asaas: NAO LIBERADA"
    Write-Host ""
    Write-Host "Relatorio:"
    Write-Host "RELATORIO-MIGRACAO-ASAAS-ORCALY.md"
    Write-Host ""
    Write-Host "Configuracao:"
    Write-Host "CONFIGURACAO-MIGRACAO-ASAAS-ORCALY.md"
    Write-Host ""
    Write-Host "Checklist:"
    Write-Host "CHECKLIST-MIGRACAO-ASAAS-ORCALY.md"
    Write-Host ""
    Write-Host "Rollback:"
    Write-Host "PLANO-ROLLBACK-MIGRACAO-ASAAS-ORCALY.md"
    Write-Host ""
    Write-Host "Backups:"
    Write-Host $BackupRoot
    Write-Host ""
    Write-Host (
        "A migracao financeira do Orcaly foi preparada de forma gradual, " +
        "reversivel e segura, preservando o Mercado Pago, implementando o " +
        "Asaas em ambiente controlado e mantendo a experiencia visual " +
        "coerente com o produto."
    ) -ForegroundColor Green
}

try {
    Test-ProjectStructure

    if (-not (Test-PowerShellSyntax $MyInvocation.MyCommand.Path)) {
        Stop-OnCriticalFailure "O proprio patcher possui erro de sintaxe."
    }

    Test-RequiredFunctions
    Expand-Payload

    if (-not $DryRun) {
        [System.IO.Directory]::CreateDirectory($BackupRoot) | Out-Null
        [System.IO.Directory]::CreateDirectory($RunRoot) | Out-Null
        Write-Utf8NoBom $ExecutionLog ""
    }

    $audit = Invoke-Audit

    if ($DryRun) {
        Write-Step ("DryRun da fase " + $Phase)
        Write-Host "Nenhum arquivo do projeto foi alterado." -ForegroundColor Magenta

        if ($Phase -eq "rollback") {
            Write-Host "O rollback restauraria o ultimo backup compativel."
        } else {
            Write-Host "Arquivos previstos:"

            foreach ($relative in Get-PayloadEntries) {
                if (
                    -not $relative.StartsWith("__special__/") -and
                    (Should-ApplyPayloadFile $relative)
                ) {
                    Write-Host (" - " + $relative)
                }
            }

            if ($Phase -in @("ui", "all")) {
                Write-Host " - app/painel/pagamentos/page.tsx (wrapper conservador)"
                Write-Host " - app/painel/assinatura/page.tsx (wrapper conservador)"
            }

            if ($Phase -in @("backend", "all")) {
                Write-Host " - app/api/checkout/plano/route.ts (fallback por provider)"
                Write-Host " - app/api/assinatura/cancelar/route.ts (fallback por provider)"
            }
        }

        Show-FinalSummary
        exit 0
    }

    if ($Phase -eq "rollback") {
        Invoke-Rollback
        Write-RollbackPlanRuntime
        Write-FinalReport
        Write-Manifests
        Show-FinalSummary
        exit 0
    }

    $changesCode = $Phase -in @(
        "infrastructure",
        "database",
        "backend",
        "ui",
        "all"
    )

    $scripts = @(Get-PackageScripts)

    if ($changesCode -and -not $SkipInitialBuild) {
        $result = Invoke-NpmCommand `
            "build inicial" `
            @("run", "build") `
            $BuildBeforeLog

        $BuildInitial = if ($result.Passed) {
            "PASSOU"
        } else {
            "FALHOU"
        }
    }

    if (
        $changesCode -and
        -not $SkipLint -and
        $scripts -contains "lint"
    ) {
        $result = Invoke-NpmCommand `
            "lint inicial" `
            @("run", "lint") `
            $LintBeforeLog

        $LintInitial = if ($result.Passed) {
            "PASSOU"
        } else {
            "FALHOU"
        }
    }

    if ($changesCode) {
        Apply-Payload
    }

    if ($Phase -in @("database", "all")) {
        Invoke-DatabaseMigration
    }

    if ($Phase -in @("ui", "backend", "all")) {
        Compare-ProtectedFunctions
    }

    Test-StaticImplementation
    Write-RollbackPlanRuntime

    if ($Phase -in @("sandbox", "cutover", "all")) {
        Invoke-SandboxChecks
    }

    if ($Phase -eq "cutover") {
        $asaasEnvironment = [string]$env:ASAAS_ENV
        $productionApproved = [string]$env:ASAAS_PRODUCTION_APPROVED

        if (
            $asaasEnvironment.ToLowerInvariant() -eq "production" -and
            $productionApproved.ToLowerInvariant() -ne "true"
        ) {
            [void]$UnresolvedItems.Add([pscustomobject]@{
                area = "Cutover"
                item = "Producao Asaas"
                status = "BLOQUEADO"
                detail = "ASAAS_PRODUCTION_APPROVED nao esta habilitado."
            })
        }

        Write-Warning (
            "A fase cutover apenas valida. Ela nao altera .env, nao ativa " +
            "producao e nao muda empresas automaticamente."
        )
    }

    Invoke-OptionalTests

    if (
        $changesCode -and
        -not $SkipLint -and
        $scripts -contains "lint"
    ) {
        $result = Invoke-NpmCommand `
            "lint final" `
            @("run", "lint") `
            $LintAfterLog

        $LintFinal = if ($result.Passed) {
            "PASSOU"
        } else {
            "FALHOU"
        }
    }

    if ($changesCode -and -not $SkipFinalBuild) {
        $result = Invoke-NpmCommand `
            "build final" `
            @("run", "build") `
            $BuildAfterLog

        $BuildFinal = if ($result.Passed) {
            "PASSOU"
        } else {
            "FALHOU"
        }

        $FinalBuildPassed = $result.Passed

        if (-not $result.Passed) {
            Restore-AllChanges
            Write-Manifests
            Stop-OnCriticalFailure (
                "O build final falhou. Os arquivos de codigo foram restaurados."
            )
        }
    }

    Write-FinalReport
    Write-Manifests
    Show-FinalSummary
} catch {
    Write-Failure $_.Exception.Message

    if (-not $DryRun -and (Test-Path -LiteralPath $RunRoot)) {
        try {
            Write-Manifests
        } catch {}

        try {
            Write-FinalReport
        } catch {}
    }

    Write-Host ""
    Write-Host "Execucao interrompida. Consulte:" -ForegroundColor Yellow
    Write-Host $ExecutionLog
    exit 1
} finally {
    Remove-Item `
        -LiteralPath $PayloadRoot `
        -Recurse `
        -Force `
        -ErrorAction SilentlyContinue

    Remove-Item `
        -LiteralPath $PayloadZip `
        -Force `
        -ErrorAction SilentlyContinue
}
